// Bundle messages from API response (flat JSON array)
const base = $('RunQuery API').first().json || {};
const rows = $input.all().map(r => r.json).filter(Boolean);

// Deduplicate by message id (keep latest created_at if dupes exist)
const seen = new Map();
for (const msg of rows) {
  const existing = seen.get(msg.id);
  if (!existing || msg.created_at > existing.created_at) {
    seen.set(msg.id, msg);
  }
}

const messages = [...seen.values()]
  .map(msg => ({
    id:        msg.id || '',
    wa_id:     msg.wa_id     || base.wa_id || '',
    name:      msg.name      || base.name  || '',
    direction: msg.direction || 'inbound',
    sender:    msg.sender    || 'user',
    text:      msg.text      || '',
    mediaType: msg.media_type || '',
    mediaUrl:  msg.media_url  || '',
    tsMs:      Number(msg.ts_ms ?? Date.now()),
    tsIso:     msg.ts_iso    || msg.created_at || new Date().toISOString(),
    createdAt: msg.created_at || '',
  }))
  .sort((a, b) => (a.tsMs || 0) - (b.tsMs || 0));

return [{
  json: {
    ...base,
    wa_id:    base.wa_id || messages[0]?.wa_id || '',
    name:     base.name  || '',
    messages,
    mergeKey: 1,
  }
}];

