const getUserJson = $('Get User API').item.json;
//const senderJson  = $('Extract Sender ID').item.json;
//const gateJson    = $('Gate after Touch').item.json;

// --- User ---
const user = getUserJson.found ? getUserJson : null;

// --- Catalog ---
let catalog = [];
try {
  catalog = $('Set Catalog').first().json.catalog || [];
} catch(e) {}

// --- Country ---
let phone_country_code = null;
let phone_country_name = null;
let phone_country_iso  = null;
let phone_flag_url     = null;
try {
  const rc = $('Resolve Country from Phone').item.json;
  phone_country_code = rc.phone_country_code || null;
  phone_country_name = rc.phone_country_name || null;
  phone_country_iso  = rc.phone_country_iso  || null;
  phone_flag_url     = rc.phone_flag_url     || null;
} catch(e) {}

// --- wa_id ---
const wa_id = (user?.wa_id || '').toString().trim();

return [{
  json: {
    ...($json || {}),
    user,
    wa_id,
    catalog,
    phone_country_code,
    phone_country_name,
    phone_country_iso,
    phone_flag_url,
    mergeKey: 1,
  }
}];

const wa_id  = $json.wa_id || '';
const digits = wa_id.replace(/\D/g, '');

let countries = [];
try { countries = $('countrycodes').all().map(i => i.json); } catch(e) {}

const sorted = [...countries].sort((a, b) =>
  b.code.replace(/\D/g,'').length - a.code.replace(/\D/g,'').length
);

let match = null;
for (const c of sorted) {
  const prefix = c.code.split(',')[0].replace(/\D/g,'');
  if (digits.startsWith(prefix)) { match = c; break; }
}

return [{ json: {
  ...$json,
  phone_country_code: match?.code    || null,
  phone_country_name: match?.country || null,
  phone_country_iso:  match?.iso     || null,
  phone_flag_url:     match?.flag_url || null,
  _resolvedCountry:   match?.country || null,
}}];

// NAME UPDATE RULES (strict):
// 1. If customer name already exists in DB → never update (manual agent only)
// 2. If name missing in DB AND WhatsApp profile name available → update from WhatsApp
// 3. If name missing in DB AND no WhatsApp name BUT AI extracted name from message → update from message

const waName      = ($json.name || '').trim();
const storedName  = ($json.user?.name || '').trim();
const wa_id       = $json.user?.wa_id || $json.wa_id;
const isNew       = !$('Get User API').item.json.found;

// Rule 1: Name already in DB → NEVER auto-update
const nameExistsInDB = !isNew && !!storedName;

// Rule 2: No name in DB + WhatsApp profile name present
const shouldPatchFromWA = !nameExistsInDB && !!waName;

// Rule 3: No name in DB + no WA name + AI extracted name from message
// The AI agent can surface a name via context.known.customerName or factsPatch.name
const aiExtractedName = (
  $json.context?.known?.customerName ||
  $json.factsPatch?.name?.stringValue ||
  ''
).trim();
const shouldPatchFromMessage = !nameExistsInDB && !waName && !!aiExtractedName;

const _shouldPatchName = shouldPatchFromWA || shouldPatchFromMessage;
const _namePatch = shouldPatchFromWA ? waName : (shouldPatchFromMessage ? aiExtractedName : '');
const _nameSource = shouldPatchFromWA ? 'whatsapp_profile' : (shouldPatchFromMessage ? 'message_mention' : 'none');

return [{
  json: {
    ...$json,
    _shouldPatchName: _shouldPatchName && !!_namePatch,
    _namePatch,
    _nameSource,   // audit trail so you can see where the name came from
    wa_id,
  }
}];

// ---------- Helpers ----------
const safeArr = (v) => Array.isArray(v) ? v : [];

const ensureState = (s) => {
  const st = (s && typeof s === 'object') ? s : {};
  const cart = (st.cart && typeof st.cart === 'object') ? st.cart : {};
  const items = safeArr(cart.items);
  const subtotal = Number.isFinite(Number(cart.subtotal)) ? Number(cart.subtotal) : 0;
  // Preserve ALL state keys (lead_stage, active, etc.) — don't strip unknown fields
  return {
    ...st,
    cart: { items, subtotal },
  };
};

// Read from API response (flat JSON, not Firestore format)
const apiResp = $json;

// wa_id fallback chain
let wa_id = apiResp.wa_id || '';
try { wa_id = wa_id || $('Gate after Touch').item.json.wa_id || ''; } catch(e) {}

// ── Field reads: API now uses snake_case ──────────────────────────────────────
// last_text / last_direction / last_message_ts (ms int) / last_message_at (ISO)
const lastText      = (apiResp.last_text      || '').trim();
const lastDirection =  apiResp.last_direction || 'inbound';

// Resolve timestamp in ms — prefer last_message_ts (integer), fall back to
// parsing last_message_at (ISO string), then fall back to current time.
let tsMsNum = null;

if (apiResp.last_message_ts != null && Number.isFinite(Number(apiResp.last_message_ts))) {
  tsMsNum = Number(apiResp.last_message_ts);
} else if (apiResp.last_message_at) {
  const parsed = Date.parse(apiResp.last_message_at);
  if (Number.isFinite(parsed)) tsMsNum = parsed;
}

// Only fall back to now if there is truly no prior message timestamp
const hasLastMessage = tsMsNum != null;
if (!hasLastMessage) tsMsNum = Date.now();

const tsIso = new Date(tsMsNum).toISOString();

// Full state including lead_stage and any other keys
const state = ensureState(apiResp.state);

const context = {
  wa_id,
  lastText,
  lastDirection,
  lastMessageAtIso: hasLastMessage ? tsIso : null,  // null = no prior messages
  lastMessageTs:    hasLastMessage ? tsMsNum : null,
  tsMs:             tsMsNum,                          // always set for downstream use
  tsIso,
  state,
  cart:             state.cart,
  lead_stage:       state.lead_stage  || null,        // surfaced for easy access
  active:           state.active      || 'active',
  last10Messages:   [],
  recentWindow:     [],
};

context.wa_id = context.wa_id || $json.wa_id || '';

return [{
  context,
  mergeKey: 1,
}];
